builder.Services.AddControllers();

// Register the training service and train the model at startup
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train model before accepting requests
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Register prediction engine pool using the trained model file.
// This must happen after training so the model file exists.
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider to include the prediction pool.
// NOTE: In production, separate training from the web host. Here we
// keep them together for demonstration purposes.
app = builder.Services.BuildServiceProvider()
    .GetRequiredService<IHost>()
    .Services.GetRequiredService<IServer>() is not null
    ? app
    : app;

app.MapControllers();
app.Run();

